import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const AdminDashboard = () => {
  const { user, token } = useAuth();
  const navigate = useNavigate();
  const [analytics, setAnalytics] = useState(null);
  const [overview, setOverview] = useState(null);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    if (user?.role !== 'admin') {
      navigate('/');
      return;
    }

    fetchDashboardData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, token]);

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const [analyticsRes, overviewRes, usersRes] = await Promise.all([
        axios.get('http://localhost:5000/api/admin/analytics', {
          headers: { Authorization: `Bearer ${token}` }
        }),
        axios.get('http://localhost:5000/api/admin/overview', {
          headers: { Authorization: `Bearer ${token}` }
        }),
        axios.get('http://localhost:5000/api/admin/users', {
          headers: { Authorization: `Bearer ${token}` }
        })
      ]);

      setAnalytics(analyticsRes.data);
      setOverview(overviewRes.data);
      console.log('Users with orders:', usersRes.data);
      setUsers(usersRes.data);
    } catch (error) {
      console.error('Failed to fetch dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div>Loading dashboard...</div>;
  }

  return (
    <div className="admin-dashboard">
      <h1>Admin Dashboard</h1>

      <div className="dashboard-tabs">
        <button 
          className={activeTab === 'overview' ? 'active' : ''}
          onClick={() => setActiveTab('overview')}
        >
          Overview
        </button>
        <button 
          className={activeTab === 'users' ? 'active' : ''}
          onClick={() => setActiveTab('users')}
        >
          Users & Orders
        </button>
      </div>

      {activeTab === 'overview' && (
        <div className="overview-tab">
          {overview && (
            <div className="dashboard-overview">
              <div className="metric-card">
                <h3>Total Orders</h3>
                <p className="metric-value">{overview.totalOrders}</p>
              </div>
              <div className="metric-card">
                <h3>Total Users</h3>
                <p className="metric-value">{overview.totalUsers}</p>
              </div>
              <div className="metric-card">
                <h3>Total Products</h3>
                <p className="metric-value">{overview.totalProducts}</p>
              </div>
              <div className="metric-card">
                <h3>Total Revenue</h3>
                <p className="metric-value">₹{overview.totalRevenue.toLocaleString()}</p>
              </div>
            </div>
          )}

          {analytics && (
            <div className="analytics-section">
              <h2>Sales Analytics</h2>

              <div className="analytics-grid">
                <div className="analytics-card">
                  <h3>Category-wise Sales</h3>
                  <table>
                    <thead>
                      <tr>
                        <th>Category</th>
                        <th>Sales</th>
                        <th>Orders</th>
                      </tr>
                    </thead>
                    <tbody>
                      {analytics.categoryWiseSales?.map(category => (
                        <tr key={category._id}>
                          <td>{category._id}</td>
                          <td>₹{category.totalSales.toLocaleString()}</td>
                          <td>{category.orderCount}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>

                <div className="analytics-card">
                  <h3>Top 10 Products</h3>
                  <table>
                    <thead>
                      <tr>
                        <th>Product</th>
                        <th>Purchases</th>
                        <th>Views</th>
                      </tr>
                    </thead>
                    <tbody>
                      {analytics.topProducts?.map(product => (
                        <tr key={product._id}>
                          <td>{product.name}</td>
                          <td>{product.purchaseCount}</td>
                          <td>{product.viewCount}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {overview?.recentOrders && (
            <div className="recent-orders">
              <h2>Recent Orders</h2>
              <table>
                <thead>
                  <tr>
                    <th>Order ID</th>
                    <th>Customer</th>
                    <th>Amount</th>
                    <th>Status</th>
                    <th>Date</th>
                  </tr>
                </thead>
                <tbody>
                  {overview.recentOrders.map(order => (
                    <tr key={order._id}>
                      <td>{order._id}</td>
                      <td>{order.userId?.name}</td>
                      <td>₹{order.totalAmount.toLocaleString()}</td>
                      <td>{order.orderStatus}</td>
                      <td>{new Date(order.orderDate).toLocaleDateString()}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {activeTab === 'users' && (
        <div className="users-tab">
          <h2>Users & Their Orders</h2>
          <div className="users-list">
            {users.map(user => (
              <div key={user._id} className="user-card">
                <div className="user-header">
                  <h3>{user.name}</h3>
                  <div className="user-stats">
                    <span className="stat">Orders: {user.totalOrders}</span>
                    <span className="stat">Spent: ₹{user.totalSpent.toLocaleString()}</span>
                  </div>
                </div>
                
                <div className="user-details">
                  <p><strong>Email:</strong> {user.email}</p>
                  {user.phone && <p><strong>Phone:</strong> {user.phone}</p>}
                  <p><strong>Joined:</strong> {new Date(user.createdAt).toLocaleDateString()}</p>
                </div>

                {user.orders.length > 0 && (
                  <div className="user-orders">
                    <h4>Recent Orders:</h4>
                    {user.orders.slice(0, 3).map(order => (
                      <div key={order._id} className="order-summary">
                        <div className="order-info">
                          <span className="order-id">#{order._id.slice(-8)}</span>
                          <span className="order-amount">₹{order.totalAmount.toLocaleString()}</span>
                          <span className={`order-status ${order.orderStatus.toLowerCase()}`}>
                            {order.orderStatus}
                          </span>
                        </div>
                        <div className="order-date">
                          {new Date(order.orderDate).toLocaleDateString()}
                        </div>
                      </div>
                    ))}
                    {user.orders.length > 3 && (
                      <p className="more-orders">+{user.orders.length - 3} more orders</p>
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
